// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer;

import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.concurrent.CopyOnWriteArrayList;

import org.eclipse.rdf4j.query.algebra.evaluation.impl.EmptyTripleSource;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.learned.LearnedJoinConfig;
import org.eclipse.rdf4j.query.parser.ParsedQuery;
import org.eclipse.rdf4j.query.parser.sparql.SPARQLParser;
import org.junit.jupiter.api.Test;

class LearnedQueryJoinOptimizerTraceSinkTest {

	private static final String QUERY = String.join("\n",
			"PREFIX ex: <http://example.com/>",
			"SELECT * WHERE {",
			"  ?s ex:p1 ?o .",
			"  ?o ex:p2 ?x .",
			"  ?x ex:p3 ?y .",
			"}");

	@Test
	void emitsPlanSelectionEvent() throws Exception {
		SPARQLParser parser = new SPARQLParser();
		ParsedQuery parsedQuery = parser.parseQuery(QUERY, null);

		EvaluationStatistics statistics = new EvaluationStatistics();
		MemoryJoinStats statsProvider = new MemoryJoinStats();
		List<OptimizationTraceEvent> events = new CopyOnWriteArrayList<>();
		OptimizationTraceSink traceSink = events::add;
		OptimizationContext context = new OptimizationContext(statistics,
				new EvaluationStatisticsCardinalityEstimator(statistics), statsProvider, traceSink);

		LearnedQueryJoinOptimizer optimizer = new LearnedQueryJoinOptimizer(context, false, new EmptyTripleSource(),
				new LearnedJoinConfig());
		optimizer.optimize(parsedQuery.getTupleExpr(), null, null);

		OptimizationTraceEvent selected = events.stream()
				.filter(event -> event.getEventType() == OptimizationTraceEvent.EventType.PLAN_SELECTED)
				.findFirst()
				.orElse(null);
		assertNotNull(selected, "Expected plan selection event from learned optimizer");
		assertTrue(selected.getAttributes().containsKey("candidate.0.signature"),
				"Expected trace event to expose top candidate signature");
		assertTrue(selected.getAttributes().containsKey("candidate.0.totalCost"),
				"Expected trace event to expose top candidate estimated total cost");
		assertTrue(selected.getAttributes().containsKey("candidate.0.totalUncertainty"),
				"Expected trace event to expose top candidate uncertainty");
		assertTrue(events.stream()
				.anyMatch(event -> event.getEventType() == OptimizationTraceEvent.EventType.PLAN_CANDIDATE
						&& event.getAttributes().containsKey("candidateIndex")),
				"Expected dedicated candidate trace events in addition to selected-plan summary");
	}
}
